`,r(e.ul,{children:[`
`,r(e.li,{children:r(e.a,{href:"https://raw.githubusercontent.com/hnaderi/teslasynth/assets/simulated-music-output-multi-channel.zip",children:"Multi-channel wav render"})}),`
